        I_AM_SORRY_BUT_OUR_STOREROOMS_ARE_EMPTY                               = 7253,  -- I am sorry, but our storerooms are empty. You will have to wait until the next supply unit has arrived.
        THE_CAMPAIGN_BATTLE_HAS_ENDED_THE_TEMPORARY_ITEM                      = 7254,  -- The campaign battle has ended. The temporary item had no effect.
        OBTAINED_TEMPORARY_ITEM_2                                             = 7255,  -- Obtained temporary item: %!
        YOU_HAVE_EARNED_ALLIED_NOTE                                           = 7256,  -- You have earned # Allied Note[/s]!
        YOUR_REPUTATION_WITHIN_THE_ALLIED_CAMPAIGN_HAS_RISEN                  = 7257,  -- Your reputation within the Allied Campaign has risen by #!
        I_AM_SORRY_BUT_YOUR_CAMPAIGN_MEDAL_HAS                                = 7258,  -- I am sorry, %, but your campaign medal has expired. I cannot issue tags to anyone not authorized by the Allied Forces. Return to your nation's capital and speak with a Campaign Evaluation Official.
        OH_HO_KEEN_TO_JOIN_A_UNION_ARE                                        = 7259,  -- Oh ho! Keen to join a Union, are we? Very well. Listen up and I shall tell you all you need to know.
        IN_ORDER_TO_BETTER_COORDINATE_ALLIED_EFFORTS_AGAINST                  = 7260,  -- In order to better coordinate Allied efforts against the beastman menace, we have instituted a system of ad hoc tactical regiments called Unions. With five units to a battlefield, union registration is open to any proven soldier in possession of Allied Tags.
        IN_RETURN_FOR_THEIR_AID_IN_ADVANCING_THE                              = 7261,  -- In return for their aid in advancing the war effort, union registrants will be eligible to earn a share of the spoils of war.
        NEEDLESS_TO_SAY_THE_CHOICEST_REWARDS_WILL_BE                          = 7262,  -- Needless to say, the choicest rewards will be reserved for those unions which make the greatest contributions in combat. Prove your mettle on the field of battle, and you will earn glory for your union, as well as a sizable bounty of your own.
        BE_FOREWARNED_THAT_YOUR_COMMITMENT_TO_YOUR_UNION                      = 7263,  -- Be forewarned that your commitment to your union comes first and foremost. In the aftermath of battle, you will not be permitted to reap rewards from your individual exploits until your union has distributed its plunder.
        CAUTION_IF_A_UNION_MEMBER_JOINS_OR_LEAVES                             = 7264,  -- Caution! If a union member joins or leaves an existing party, that party's treasure pool will be distributed automatically and immediately.
        REGISTER_FOR_A_UNION_YES_NO                                           = 7265,  -- Register for a union? Yes. No.
        FROM_YOUR_CURRENT_UNION_YES_NO                                        = 7266,  -- [Transfer/Resign] from your current union? Yes. No.
