        I_KNOW_THIS_SOUNDS_CRAZY_BUT_I_HEARD                                  = 7778,  -- I know this sounds crazy, but I heard the voice of my dead father the last time I was in Grauberg...
        HE_WAS_KILLED_OUT_THERE_WHILE_INVESTIGATING_A                         = 7779,  -- He was killed out there while investigating a high-quality crystal deposit--I'm sure he was trying to reach me from beyond the grave.
        WHAT_COULD_HE_HAVE_BEEN_TRYING_TO_TELL                                = 7780,  -- What could he have been trying to tell me? The memory of that faint whisper has pushed everything else from my mind.
        I_THINK_OF_NOTHING_BUT_GOING_BACK_THERE                               = 7781,  -- I think of nothing but going back there to search out his spirit, but deserting my post is not an option...
        WHAT_COULD_MY_FATHER_HAVE_BEEN_TRYING_TO                              = 7782,  -- What could my father have been trying to tell me...?
