        YOU_RE_JUST_MAKING_FUN_OF_ME_NOW                                      = 7786,  -- You're just making fun of me now... How would you know what my father sounded like?
        THE_GHOST_OF_A_GALKAN_SOLDIER_AND_THOSE                               = 7787,  -- The ghost of a Galkan soldier... And those were the words he used?
        IT_CERTAINLY_SOUNDS_LIKE_SOMETHING_MY_FATHER_WOULD                    = 7788,  -- It certainly sounds like something my father would say...
        IT_WAS_JUST_THE_TWO_OF_US_WHEN                                        = 7789,  -- It was just the two of us when I was growing up, you see.
        AND_HE_WOULD_ALWAYS_PROMISE_TO_RETURN_WHENEVER                        = 7790,  -- And he would always promise to return whenever he was called away on duty.
        IT_MUST_BE_THE_BROKEN_PROMISE_THAT_TIES                               = 7791,  -- It must be the broken promise that ties him to that place...
        I_THANK_YOU_FOR_GOING_THROUGH_ALL_THIS                                = 7792,  -- I thank you for going through all this trouble for me. Maybe I'll get a chance to meet this ghost for myself one day.
        NOW_THAT_I_VE_HEARD_HIS_MESSAGE_I                                     = 7793,  -- Now that I've heard his message, I can focus on my duty and make my father proud.
        BEYOND_THIS_PASS_LIES_THE_JUGNER_FOREST_BE                            = 7794,  -- Beyond this pass lies the Jugner Forest. Be on your guard, as the shadows teem with deadly Orcish scouts.
        ONE_MOMENT_SIR_MA_AM_I_MUST_INFORM                                    = 7795,  -- One moment, sir/ma'am]. I must inform you that the area ahead has been designated highly dangerous, and we strongly recommend that all civilians avoid passage when possible.
        TURN_AROUND_AND_RETURN_THE_WAY_YOU_CAME                               = 7796,  -- Turn around and return the way you came, and you will find a stronghold within the Coveffe Barrows. The guards will be able to offer you protection.
