        SHEESH_ARE_YOU_STILL_GOING_ON_ABOUT_THAT                              = 8393,  -- Sheesh! Are you still going on about that? Doesn't it bother you that something...unsavory might develop between those two?
        W_WELL_I                                                              = 8394,  -- W-well, I...
        OF_COURSE_IT_BOTHERS_YOU_AND_THAT_S                                   = 8395,  -- Of course it bothers you, and that's why we're doing this! Come on, we're almost there!
        AH_LILISETTE_WAAAIT                                                   = 8396,  -- Ah, Lilisette! Waaait!
        GRRR_HAD_ONLY_OUR_RATIONS_HELD_OUT_THESE                              = 8397,  -- Grrr! Had only our rations held out, these foul fiends would not harrow us so! Where is that Chimene!? 'Tis long past time she arrived with the rice balls!
        IT_APPEARS_THE_BEASTMEN_HAVE_YET_TO_PASS                              = 8398,  -- It appears the beastmen have yet to pass through here.
        AYE_I_WOULD_CONCUR                                                    = 8399,  -- Aye, I would concur.
        SIR_RAGELISE_PRAY_FORGIVE_MY_FORTHRIGHTNESS_BUT_THE                   = 8400,  -- Sir Ragelise. Pray forgive my forthrightness...but the moment seizes me, and I must speak my mind. Oft have I dreamed of the pleasure of your exclusive company. That we're on a peril-fraught mission serves only to stoke the fires of my--
        AH_HAH_HAH_A_AYE_TIS_A_STRANGE                                        = 8401,  -- Ah hah hah! A-aye, 'tis a strange coincidence, is it not? That we should find ourselves utterly alone, with not a single underling in sight?
        BLUSH_SIR_RAGELISE                                                    = 8402,  -- <Blush> Sir Ragelise...
        SIR_NOILLURIE                                                         = 8403,  -- Sir Noillurie!
        ID_8404                                                               = 8404,  -- !?
        CHIMENE_WHAT_IS_THE_MEANING_OF_THIS_INTRUS                            = 8405,  -- Chimene!? What is the meaning of this intrus--I mean, at whose command are you here!?
        I_BRING_THE_BATCH_OF_MARTIAL_RICE_BALLS                               = 8406,  -- I bring the batch of martial rice balls as per your request, sir!
        AS_PER_MY_REQUEST_YOU_SAY_WHAT_ARE                                    = 8407,  -- As per my request, you say? What are our unit's words, pray tell?
        TH_THAT_WOULD_BE_MARCH_NOT_WITHOUT_MARTIAL                            = 8408,  -- Th-that would be March Not Without Martial Rice Balls, sir!
        DO_YOU_MEAN_TO_IMPLY_THEN_THAT_I                                      = 8409,  -- Do you mean to imply then, that I, of all people, have been remiss in keeping true to our most sacred motto?
        I_I_WOULD_NOT_DREAM_OF_IT_SIR                                         = 8410,  -- I-I would not dream of it, sir. It...it's just that but moments ago...<mumble, mumble>...
        L_LILISETTE_WHERE_HAVE_YOU_GONE_LILISETTE                             = 8411,  -- L-Lilisette? Where have you gone? Lilisette!
