        BLUSH_UM_Y_YOU_SEE_I_I_UH                                             = 8415,  -- <Blush> Um...y-you see... I-I...uh...
        SIR_NOILLURIE_2                                                       = 8416,  -- Sir Noillurie!
        I_VE_UM_BROUGHT_THE_MARTIAL_RICE_BALLS                                = 8417,  -- I've, um...brought the martial rice balls as bade, sir!
        ID_8418                                                               = 8418,  -- ...
        YOU_DID_REQUEST_THEM_I_HOPE                                           = 8419,  -- You...did request them...I hope?
        AYE_NO_MISTAKE_ABOUT_IT_I_WAS_UNDER                                   = 8420,  -- Aye, no mistake about it. I was under the impression, however, that they would arrive a deal sooner. At once were the words you used, were they not?
        TH_THEY_WERE_SIR                                                      = 8421,  -- Th-they were, sir!
        ON_ACCOUNT_OF_YOUR_TARDINESS_THE_RED_ROSES                            = 8422,  -- On account of your tardiness, the Red Roses were left with no recourse but to the fight the enemy on empty stomachs. Your peers shan't look kindly upon this, do not doubt it.
        ID_8423                                                               = 8423,  -- ...!
        F_FORGIVE_ME_SIR_OUR_SUPPLY_OF_RELISH                                 = 8424,  -- F-forgive me, sir! Our supply of relish had been exhausted, and--
        SPARE_ME_YOUR_EXCUSES_BE_REMINDED_THAT_THIS                           = 8425,  -- Spare me your excuses. Be reminded that this isn't the first time you've vexed me in matters pertaining to rice balls.
        WHAT_MANNER_OF_PUNISHMENT_WOULD_BE_APT_TO                             = 8426,  -- What manner of punishment would be apt to mend you of your chronic untimeliness, I wonder...
        PUNISHMENT_M_MERCY_SIR_NOILLURIE                                      = 8427,  -- Punishment!? M-mercy, Sir Noillurie!
